const body = $json.body ?? $json;
const action = String(body.action ?? 'plan');
const specialist = String(body.specialist ?? 'repo-architect');
const riskTier = String(body.riskTier ?? 'P2');
const mode = String(body.mode ?? 'read-only');
const commandText = String(body.commandText ?? '');
const taskId = `agent-${Date.now()}`;
const accepted = mode === 'read-only' || action === 'approve';
const status = accepted ? 'accepted' : 'approval_required';
return [{ json: { taskId, status, action, specialist, riskTier, mode, commandText, message: accepted ? `Task ${taskId} accepted for ${specialist}.` : `Approval required before running ${action}.` } }];
